from dataclasses import dataclass


@dataclass
class SamplingStrategy:
    default_rate: float = 0.05
    # Strata with elevated rates — important flows get more coverage
    tier_rates: dict[str, float] = None
    feature_rates: dict[str, float] = None

    def __post_init__(self):
        if self.tier_rates is None:
            self.tier_rates = {
                "enterprise": 0.20,   # high-value customers, catch regressions fast
                "pro": 0.10,
                "free": 0.02,         # high volume; lower rate to control eval cost
            }
        if self.feature_rates is None:
            self.feature_rates = {
                "medical_summary": 0.50,  # safety-critical — oversample aggressively
                "legal_review": 0.30,
                "code_generation": 0.10,
                "chat": 0.05,
            }

    def rate_for(self, tier: str, feature: str) -> float:
        tier_rate = self.tier_rates.get(tier, self.default_rate)
        feature_rate = self.feature_rates.get(feature, self.default_rate)
        # Take the higher of the two rates
        return max(tier_rate, feature_rate)
